async function _extractViaCfWorker(link) {
  const auth = process.env.CF_WORKER_AUTH || '';
  if (!auth) return null;
  try {
    const workerUrl = `${CF_WORKER_URL}/?uprot=1&extract=1&auth=${encodeURIComponent(auth)}&url=${encodeURIComponent(link)}`;
    const resp = await fetch(workerUrl, {
      headers: { 'User-Agent': UA },
      signal: AbortSignal.timeout(40000),
    });
    if (!resp.ok) {
      console.warn('[Uprot] CF Worker returned', resp.status);
      return null;
    }
    const data = await resp.json();
    if (data.error) {
      console.warn('[Uprot] CF Worker error:', data.error);
      return null;
    }
