const { fetchWithCloudscraper } = require('./src/utils/fetcher');
const { getProviderUrl } = require('./src/provider_urls');

(async () => {
  const base = (getProviderUrl('cb01') || 'https://cb01uno.uno').replace(/\/+$/, '');
  console.log('CB01 base:', base);

  const url = base + '/serietv/?s=Will+%26+Grace';
  console.log('Search URL:', url);
  const html = await fetchWithCloudscraper(url, { referer: base + '/serietv/' });
  if (!html) { console.log('No HTML returned'); return; }
  console.log('HTML length:', html.length);

  // Find card-content sections
  const cards = [...html.matchAll(/<div[^>]+class="card-content"([\s\S]*?)<\/div>/gi)];
  console.log('Cards found:', cards.length);
  for (const c of cards) {
    const href = (c[1].match(/href=["']([^"']+)["']/) || [])[1] || '';
    const title = (c[1].match(/<h3[^>]*>([\s\S]*?)<\/h3>/) || [])[1] || '';
    const clean = title.replace(/<[^>]+>/g, '').trim();
    console.log(' -', clean, '→', href.substring(0, 100));
  }

  // Also try "Will and Grace" without &
  console.log('\n--- Also try "Will and Grace" ---');
  const url2 = base + '/serietv/?s=Will+and+Grace';
  const html2 = await fetchWithCloudscraper(url2, { referer: base + '/serietv/' });
  if (!html2) { console.log('No HTML returned'); return; }
  const cards2 = [...html2.matchAll(/<div[^>]+class="card-content"([\s\S]*?)<\/div>/gi)];
  console.log('Cards found:', cards2.length);
  for (const c of cards2) {
    const href = (c[1].match(/href=["']([^"']+)["']/) || [])[1] || '';
    const title = (c[1].match(/<h3[^>]*>([\s\S]*?)<\/h3>/) || [])[1] || '';
    const clean = title.replace(/<[^>]+>/g, '').trim();
    console.log(' -', clean, '→', href.substring(0, 100));
  }

  // If we found a page, check its content for episodes + maxstream/uprot links
  const allCards = [...cards, ...cards2];
  if (allCards.length > 0) {
    const firstHref = (allCards[0][1].match(/href=["']([^"']+)["']/) || [])[1];
    if (firstHref) {
      console.log('\n--- Fetching show page:', firstHref, '---');
      const pageHtml = await fetchWithCloudscraper(firstHref, { referer: base + '/serietv/' });
      if (pageHtml) {
        console.log('Page length:', pageHtml.length);

        // Find sp-head sections (STAGIONE headers)
        const spHeads = [...pageHtml.matchAll(/<div[^>]+class="sp-head[^"]*"[^>]*>([\s\S]*?)<\/div>/gi)];
        console.log('Season headers:', spHeads.length);
        for (const s of spHeads) {
          const text = s[1].replace(/<[^>]+>/g, '').trim();
          console.log('  SEASON:', text);
        }

        // Check for stayonline links
        const stayLinks = (pageHtml.match(/stayonline\.pro[^"']*/gi) || []);
        console.log('Stayonline links:', stayLinks.length);

        // Check for uprot links  
        const uprotLinks = (pageHtml.match(/uprot\.net[^"']*/gi) || []);
        console.log('Uprot links:', uprotLinks.length);

        // Check episode patterns for S1E1
        const ep1_1 = pageHtml.match(/1&#215;01|1x01|S01E01/gi);
        console.log('Episode 1x01 matches:', ep1_1);

        // Show a sample ep block
        const epMatch = pageHtml.match(/1&#215;01[\s\S]*?(?=\d+&#215;\d+|<\/p>)/i);
        if (epMatch) {
          console.log('\n--- Ep 1x01 block (400ch): ---');
          console.log(epMatch[0].substring(0, 400));
        }
      }
    }
  }
})();
