# Create docs/copilot-memory folder and copy all .md files
$src = "C:\Users\vitob\AppData\Roaming\Code\User\workspaceStorage\090965633131c346bdaa5c62e05162dd\GitHub.copilot-chat\memory-tool\memories"
$dst = "C:\Users\vitob\Desktop\bot telegram\Streaming Koreano\StreamFusionMail\docs\copilot-memory"
New-Item -ItemType Directory -Path $dst -Force | Out-Null

# Copy session memories (the long GUID folder)
